customHandlers.d_sqs4bl:
function(ctx) {
    var parts = ctx.vodId.split("###");
    if (parts.length < 4 || parts[2] === "_" || parts[2] === "") return { list: [] };
    var title = parts[1], lastVideoGuid = parts[2], logo = parts[3];
    var infoUrl = "https://api.cntv.cn/video/videoinfoByGuid?guid=" + lastVideoGuid + "&serviceId=tvcctv";
    var infoResp = req(infoUrl);
    var infoJson;
    try { infoJson = JSON.parse(infoResp.content); } catch(e) { return { list: [] }; }
    if (!infoJson.ctid) return { list: [] };
    var topicId = infoJson.ctid;
    var channel = infoJson.channel || "";
    var listUrl = "https://api.cntv.cn/NewVideo/getVideoListByColumn?id=" + topicId + "&d=&p=1&n=100&sort=desc&mode=0&serviceId=tvcctv&t=json";
    var listResp = req(listUrl);
    var listJson;
    try { listJson = JSON.parse(listResp.content); } catch(e) { return { list: [] }; }
    var videos = (listJson.data && listJson.data.list) ? listJson.data.list : [];
    var playUrls = [];
    for (var i = 0; i < videos.length; i++) {
      var video = videos[i];
      var playId = video.pid || video.vid || video.guid;
      if (playId) playUrls.push(video.title + "$" + playId);
    }
    if (playUrls.length === 0) return { list: [] };
    return { list: [{ vod_id: ctx.vodId, vod_name: title, vod_pic: logo, type_name: channel, vod_play_from: "央视", vod_play_url: playUrls.join("#") }] };
  }

customHandlers.p_0hyo2f:
function(ctx) {
    var pid = ctx.id;
    if (!pid) return { parse: 0, playUrl: "", url: "" };
    var url = "https://vdn.apps.cntv.cn/api/getHttpVideoInfo.do?pid=" + pid;
    var resp = req(url);
    var json;
    try { json = JSON.parse(resp.content); } catch(e) { return { parse: 0, playUrl: "", url: "" }; }
    var hls = json.hls_url || "";
    return { parse: 0, playUrl: "", url: hls };
  }

customHandlers.h_e2y135:
function(ctx) {
    var resp = req("https://api.cntv.cn/lanmu/columnSearch?p=1&n=20&serviceId=tvcctv&t=json");
    var json;
    try {
      json = JSON.parse(resp.content);
    } catch(e) {
      console.log("列表JSON解析失败: " + e.message);
      return [];
    }
    var data = json;
data = data["response"];
data = data["docs"];
    if (!Array.isArray(data)) return [];
    var result = [];
    for (var i = 0; i < data.length; i++) {
      var item = data[i];
      var columnId = item.id || item._id || "";
      var columnName = item["column_name"] || "无标题";
      var lastVideoGuid = (function(obj) { try { let v = obj; for (let p of ["lastVIDE","videoSharedCode"]) { if (v && typeof v === 'object') v = v[p]; else return '_'; } return v || '_'; } catch(e) { return '_'; } })(item);
      var logo = item["column_logo"] || "";
      var compositeId = columnId + "###" + columnName + "###" + (lastVideoGuid === '_' ? '_' : lastVideoGuid) + "###" + logo;
      result.push({ vod_id: compositeId, vod_name: columnName, vod_pic: logo });
    }
    return result;
  }
